import sqlite3
from contextlib import contextmanager

@contextmanager
def db_transaction(db):
    try:
        yield db.cursor()
        db.commit()
    except Exception as e:
        db.rollback()
        raise e

class FileAccessControlSystem:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()

    def check_permission(self, user_id, file_id):
        with db_transaction(self.conn) as cursor:
            cursor.execute("SELECT access_level FROM users WHERE id=?", (user_id,))
            user_access_level = cursor.fetchone()[0]
            cursor.execute("SELECT permission FROM permissions WHERE user_id=? AND file_id=?", (user_id, file_id))
            permission = cursor.fetchone()
            if permission and permission[0] >= user_access_level:
                return True
        return False

    def get_file_contents(self, user_id, file_id):
        if self.check_permission(user_id, file_id):
            with db_transaction(self.conn) as cursor:
                cursor.execute("SELECT contents FROM files WHERE id=?", (file_id,))
                return cursor.fetchone()[0]
        else:
            raise PermissionError("User does not have permission to access the file")

    def update_permission(self, user_id, file_id, new_permission):
        with db_transaction(self.conn) as cursor:
            cursor.execute("UPDATE permissions SET permission=? WHERE user_id=? AND file_id=?", (new_permission, user_id, file_id))

